12	/* Data type to define the protocol through which BL/WL can be manipulated */
13	enum e_blwl_protocol_type {
14	  BLWL_PROTOCOL_FLATTEN,
15	  BLWL_PROTOCOL_DECODER,
16	  BLWL_PROTOCOL_SHIFT_REGISTER,
17	  NUM_BLWL_PROTOCOL_TYPES
18	};
19	constexpr std::array<const char*, NUM_BLWL_PROTOCOL_TYPES>
20	  BLWL_PROTOCOL_TYPE_STRING = {{"flatten", "decoder", "shift_register"}};
21	
22	/********************************************************************
23	 * A data structure to store configuration protocol information
24	 *******************************************************************/
25	class ConfigProtocol {
26	 public: /* Constructors */
27	  ConfigProtocol();
28	
29	 public: /* Public Accessors */
30	  e_config_protocol_type type() const;
31	  std::string memory_model_name() const;
32	  CircuitModelId memory_model() const;
33	  int num_regions() const;
34	
35	  /* Find the number of programming clocks, only valid for configuration chain
36	   * type! */
37	  size_t num_prog_clocks() const;
38	  /* Get information of the programming clock port: name and width */
39	  openfpga::BasicPort prog_clock_port_info() const;
40	  /* Get a list of programming clock pins, flatten from the programming clock
41	   * port */
42	  std::vector<openfpga::BasicPort> prog_clock_pins() const;
43	  /* Get a list of programming clock ports */
44	  std::string prog_clock_pin_ccff_head_indices_str(
45	    const openfpga::BasicPort& port) const;
46	  std::vector<size_t> prog_clock_pin_ccff_head_indices(
47	    const openfpga::BasicPort& port) const;
48	
49	  e_blwl_protocol_type bl_protocol_type() const;
50	  std::string bl_memory_model_name() const;
51	  CircuitModelId bl_memory_model() const;
52	  size_t bl_num_banks() const;
53	  e_blwl_protocol_type wl_protocol_type() const;
54	  std::string wl_memory_model_name() const;
55	  CircuitModelId wl_memory_model() const;
56	  size_t wl_num_banks() const;
57	
58	  /* QL Memory Bank Config Setting */
59	  const QLMemoryBankConfigSetting* ql_memory_bank_config_setting() const;
60	
61	 public: /* Public Mutators */
62	  void set_type(const e_config_protocol_type& type);
63	  void set_memory_model_name(const std::string& memory_model_name);
64	  void set_memory_model(const CircuitModelId& memory_model);
65	  void set_num_regions(const int& num_regions);
66	
67	  /* Add the programming clock port */
68	  void set_prog_clock_port(const openfpga::BasicPort& port);
69	  /* Add a pair of programming clock pin and ccff head indices. This API will
70	   * parse the index list, e.g., "0,1" to a vector of integers [0 1] */
71	  void set_prog_clock_pin_ccff_head_indices_pair(
72	    const openfpga::BasicPort& pin, const std::string& indices_str);
73	
74	  void set_bl_protocol_type(const e_blwl_protocol_type& type);
75	  void set_bl_memory_model_name(const std::string& memory_model_name);
76	  void set_bl_memory_model(const CircuitModelId& memory_model);
77	  void set_bl_num_banks(const size_t& num_banks);
78	  void set_wl_protocol_type(const e_blwl_protocol_type& type);
79	  void set_wl_memory_model_name(const std::string& memory_model_name);
80	  void set_wl_memory_model(const CircuitModelId& memory_model);
81	  void set_wl_num_banks(const size_t& num_banks);
82	
83	  /* QL Memory Bank Config Setting */
84	  QLMemoryBankConfigSetting* get_ql_memory_bank_config_setting();
85	
86	 public: /* Public validators */
87	  /* Check if internal data has any conflicts to each other. Return number of
88	   * errors detected */
89	  int validate() const;
90	
91	 private: /* Private validators */
92	  /* For configuration chains, to validate if
93	   * - programming clocks is smaller than the number of regions
94	   * - programming clocks does not have any conflicts in controlling regions (no
95	   * overlaps)
96	   * - each region has been assigned to a programming clock
97	   * Return number of errors detected
98	   */
99	  int validate_ccff_prog_clocks() const;
100	
101	 private: /* Internal data */
102	  /* The type of configuration protocol.
103	   * In other words, it is about how to organize and access each configurable
104	   * memory
105	   */
106	  e_config_protocol_type type_;
107	
108	  /* The circuit model of configuration memory to be used in the protocol */
109	  std::string memory_model_name_;
110	  CircuitModelId memory_model_;
111	
112	  /* Number of configurable regions */
113	  int num_regions_;
114	
115	  /* Programming clock managment: This is only applicable to configuration chain
116	   * protocols */
117	  openfpga::BasicPort prog_clk_port_;
118	  std::vector<std::vector<size_t>> prog_clk_ccff_head_indices_;
119	  char INDICE_STRING_DELIM_;
120	
121	  /* BL & WL protocol: This is only applicable to memory-bank configuration
122	   * protocols
123	   * - type:               defines which protocol to be used. By default, we
124	   * consider decoders
125	   * - bl/wl_memory_model: defines the circuit model to be used when building
126	   * shift register chains for BL/WL configuration. It must be a valid CCFF
127	   * circuit model. This is only applicable when shift-register protocol is
128	   * selected for BL or WL.
129	   * - bl/wl_num_banks:    defines the number of independent shift register
130	   * chains (with separated head and tail ports) for a given BL protocol per
131	   * configuration region
132	   */
133	  e_blwl_protocol_type bl_protocol_type_ = BLWL_PROTOCOL_DECODER;
134	  std::string bl_memory_model_name_;
135	  CircuitModelId bl_memory_model_;
136	  size_t bl_num_banks_;
137	  e_blwl_protocol_type wl_protocol_type_ = BLWL_PROTOCOL_DECODER;
138	  std::string wl_memory_model_name_;
139	  CircuitModelId wl_memory_model_;
140	  size_t wl_num_banks_;
141	
142	  /* QL Memory Bank Config Setting */
143	  QLMemoryBankConfigSetting ql_memory_bank_config_setting_;
144	};
145	
146	#endif
