16	/* namespace openfpga begins */
17	namespace openfpga {
18	
19	/********************************************************************
20	 * This file include the declaration of data structures
21	 * to store physical tile annotation, including
22	 * 1. global port definition where a tile port can be treated as a
23	 *    global port of the FPGA fabric
24	 *
25	 * Note:
26	 * 1. Keep this data structure as general as possible. It is supposed
27	 *    to contain the raw data from architecture XML! If you want to link
28	 *    to other data structures, please create another one in other header files
29	 *******************************************************************/
30	class TileAnnotation {
31	 public: /* Types */
32	  typedef vtr::vector<TileGlobalPortId, TileGlobalPortId>::const_iterator
33	    global_port_iterator;
34	  /* Create range */
35	  typedef vtr::Range<global_port_iterator> global_port_range;
36	
37	 public: /* Constructor */
38	  TileAnnotation();
39	
40	 public: /* Public accessors: aggregators */
41	  global_port_range global_ports() const;
42	  std::vector<std::string> tiles_to_merge_ports() const;
43	  std::vector<std::string> tile_ports_to_merge(
44	    const std::string& tile_name) const;
45	  std::vector<std::pair<std::string, std::string>> physical_equivalent_sites()
46	    const;
47	
48	 public: /* Public accessors */
49	  std::string global_port_name(const TileGlobalPortId& global_port_id) const;
50	  std::vector<std::string> global_port_tile_names(
51	    const TileGlobalPortId& global_port_id) const;
52	  std::vector<BasicPort> global_port_tile_ports(
53	    const TileGlobalPortId& global_port_id) const;
54	  std::vector<vtr::Point<size_t>> global_port_tile_coordinates(
55	    const TileGlobalPortId& global_port_id) const;
56	  bool global_port_is_clock(const TileGlobalPortId& global_port_id) const;
57	  bool global_port_is_set(const TileGlobalPortId& global_port_id) const;
58	  bool global_port_is_reset(const TileGlobalPortId& global_port_id) const;
59	  bool global_port_thru_dedicated_network(
60	    const TileGlobalPortId& global_port_id) const;
61	  std::string global_port_clock_arch_tree_name(
62	    const TileGlobalPortId& global_port_id) const;
63	  size_t global_port_default_value(
64	    const TileGlobalPortId& global_port_id) const;
65	
66	  /** @brief Check if a given tile port should be merged or not */
67	  bool is_tile_port_to_merge(const std::string& tile_name,
68	                             const std::string& port_name) const;
69	
70	  bool is_physical_equivalent_site_defined(
71	    const std::string& tile_name, const std::string& subtile_name) const;
72	  std::string physical_equivalent_site(const std::string& tile_name,
73	                                       const std::string& subtile_name) const;
74	
75	 public: /* Public mutators */
76	  /* By default, we do not set it as a clock.
77	   * Users should set it through the set_global_port_is_clock() function
78	   */
79	  TileGlobalPortId create_global_port(const std::string& port_name);
80	  /* Add tile port information */
81	  void add_global_port_tile_information(const TileGlobalPortId& global_port_id,
82	                                        const std::string& tile_name,
83	                                        const BasicPort& tile_port,
84	                                        const vtr::Point<size_t>& tile_coord);
85	  void set_global_port_is_clock(const TileGlobalPortId& global_port_id,
86	                                const bool& is_clock);
87	  void set_global_port_clock_arch_tree_name(
88	    const TileGlobalPortId& global_port_id, const std::string& clock_tree_name);
89	  void set_global_port_is_set(const TileGlobalPortId& global_port_id,
90	                              const bool& is_set);
91	  void set_global_port_is_reset(const TileGlobalPortId& global_port_id,
92	                                const bool& is_reset);
93	  void set_global_port_default_value(const TileGlobalPortId& global_port_id,
94	                                     const size_t& default_value);
95	
96	  int add_merge_subtile_ports(const std::string& tile_name,
97	                              const std::string& port_name);
98	
99	  int set_physical_equivalent_site(const std::string& tile_name,
100	                                   const std::string& subtile_name,
101	                                   const std::string& site_name);
102	
103	 public: /* Public validator */
104	  bool valid_global_port_id(const TileGlobalPortId& global_port_id) const;
105	  /* Validate attributes of a given global port
106	   * - A port can only be defined as clock or set or reset
107	   */
108	  bool valid_global_port_attributes(
109	    const TileGlobalPortId& global_port_id) const;
110	
