58	  typedef vtr::Range<fabric_key_iterator> fabric_key_range;
59	  typedef vtr::Range<fabric_bit_line_bank_iterator> fabric_bit_line_bank_range;
60	  typedef vtr::Range<fabric_word_line_bank_iterator>
61	    fabric_word_line_bank_range;
62	  typedef vtr::Range<fabric_sub_key_iterator> fabric_sub_key_range;
63	  typedef vtr::Range<fabric_key_module_iterator> fabric_key_module_range;
64	
65	 public: /* Constructors */
