23	/********************************************************************
24	 * A data structure to describe a clock network
25	 * A clock network consists of a number of clock trees
26	 * each of which has:
27	 * - a unique id
28	 * - different entry point
29	 *
30	 * Typical usage:
31	 * --------------
32	 *   // Create an object of clock network
33	 *   ClockNetwork clk_ntwk;
34	 *   // Create a new clock tree which contains 8 clock pins
35	 *   ClockTreeId clk_tree_id = clk_ntwk.create_tree("tree1")
36	 *   // Add a spine to the clock tree
37	 *   ClockSpineId clk_spine_id = clk_ntwk.create_spine("tree1_spine0");
38	 *
39	 *******************************************************************/
40	class ClockNetwork {
41	 public: /* Types */
